import React, { useEffect } from 'react';
import AOS from 'aos';
import 'aos/dist/aos.css';
import styled from 'styled-components';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faCode, faLaptopCode, faUsers, faChalkboardTeacher } from '@fortawesome/free-solid-svg-icons';

const HeroSection = styled.section`
  min-height: 100vh;
  display: flex;
  align-items: center;
  padding: 0 10%;
  position: relative;
  overflow: hidden;
`;

const HeroText = styled.div`
  max-width: 600px;
  z-index: 2;

  h1 {
    font-size: 3.5rem;
    margin-bottom: 20px;
    color: white;
  }

  .highlight {
    color: #00FFFF;
    font-family: 'Orbitron', sans-serif;
    font-size: 4rem;
    position: relative;
    display: inline-block;
  }

  p {
    font-size: 1.3rem;
    margin-bottom: 30px;
    line-height: 1.6;
    color: rgba(255, 255, 255, 0.9);
  }
`;

const HeroButtons = styled.div`
  display: flex;
  gap: 20px;

  a {
    text-decoration: none;
    color: rgb(59, 0, 87);
    background: linear-gradient(45deg, #00BFFF, #00FFFF);
    padding: 10px 25px;
    border-radius: 30px;
    font-size: 20px;
    transition: transform 0.3s ease;

    &:hover {
      transform: translateY(-3px);
    }
  }
`;

const Hero = () => {
  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: true
    });
  }, []);

  return (
    <HeroSection>
      <HeroText data-aos="fade-right">
        <h1>Welcome to <br /><span className="highlight">Optimus</span></h1>
        <p>
          Empowering innovation through workshops, hackathons, and a tech-driven community. 
          Join us in shaping the future of technology.
        </p>
        <HeroButtons>
          <a href="#" target="_blank" data-aos="zoom-in" data-aos-delay="300" id="dynamic-link">
            Join Now
          </a>
          <a href="/events" data-aos="zoom-in" data-aos-delay="400">
            Explore Events
          </a>
        </HeroButtons>
      </HeroText>
    </HeroSection>
  );
};

export default Hero;
